export const reactCourse = {
  id: 'react', title: 'React', description: 'Declarative JavaScript library for building user interfaces.',
  officialDocs: 'https://react.dev/', tutorialLink: 'https://react.dev/learn', exerciseLink: 'https://www.w3schools.com/react/react_exercises.asp',
  sections: [
    { title: 'What is React', content: `React is a declarative, component-based JavaScript library for building user interfaces. Created by Facebook (Meta) in 2013, it revolutionized frontend development with its Virtual DOM, one-way data flow, and component-based architecture.\n\nReact is "declarative" — you describe what the UI should look like for a given state, and React efficiently updates the actual DOM. This is fundamentally different from "imperative" DOM manipulation where you manually tell the browser what to change.\n\nReact is not a full framework — it handles only the View layer. For routing, state management, and data fetching, you combine React with libraries (React Router, Redux/Zustand, TanStack Query) or use full frameworks built on React (Next.js, Remix).`, keyPoints: ['Declarative UI — describe what, React handles how.', 'Component-based architecture for reusability.', 'Virtual DOM for efficient updates.', 'Not a full framework — handles only the View layer.'] },
    { title: 'Installation & Create App', content: `Modern React projects use Vite as the build tool. Create React App (CRA) is deprecated. Vite provides fast startup, hot module replacement (HMR), and optimized builds.\n\nFor full-stack applications, consider Next.js (server-side rendering, API routes, file-based routing) or Remix (full-stack web framework with nested routes). These frameworks handle routing, data loading, and deployment out of the box.`, code: `# Create with Vite (recommended)\nnpm create vite@latest my-app -- --template react\ncd my-app\nnpm install\nnpm run dev\n\n# Create with Next.js (full-stack)\nnpx create-next-app@latest my-app\n\n# Project structure\nmy-app/\n├── public/              # Static assets\n├── src/\n│   ├── components/      # Reusable UI components\n│   ├── pages/           # Page components\n│   ├── hooks/           # Custom hooks\n│   ├── data/            # Data & API logic\n│   ├── App.jsx          # Root component\n│   ├── main.jsx         # Entry point\n│   └── index.css        # Global styles\n├── index.html\n├── package.json\n└── vite.config.js`, codeLabel: 'Project Setup', keyPoints: ['Use Vite for new React projects (CRA is deprecated).', 'Next.js for full-stack applications with SSR.', 'Organize: components/, pages/, hooks/, data/.', 'npm run dev starts the development server.'] },
    { title: 'JSX & Components', content: `JSX (JavaScript XML) is a syntax extension that lets you write HTML-like code inside JavaScript. It is not HTML — it is syntactic sugar for React.createElement() calls. JSX must return a single root element (use fragments <> </> for multiple elements without extra DOM nodes).\n\nComponents are the building blocks of React applications. They are JavaScript functions that return JSX. Each component is a self-contained, reusable piece of UI with its own logic and appearance.\n\nExpressions inside JSX use curly braces: {variable}, {condition && <Element />}, {items.map(item => <Item key={item.id} />)}. Important: every item in a list needs a unique key prop for React to efficiently track changes.`, code: `// Functional component\nfunction Greeting({ name, isLoggedIn }) {\n  return (\n    <div className="greeting">\n      <h1>Hello, {name}!</h1>\n      {isLoggedIn ? (\n        <p>Welcome back!</p>\n      ) : (\n        <button>Log In</button>\n      )}\n    </div>\n  );\n}\n\n// List rendering with keys\nfunction CourseList({ courses }) {\n  return (\n    <ul>\n      {courses.map(course => (\n        <li key={course.id}>\n          <h3>{course.title}</h3>\n          <p>{course.description}</p>\n        </li>\n      ))}\n    </ul>\n  );\n}\n\n// Fragment (no extra DOM node)\nfunction Header() {\n  return (\n    <>\n      <nav>Navigation</nav>\n      <h1>Title</h1>\n    </>\n  );\n}`, codeLabel: 'JSX & Components', keyPoints: ['JSX returns HTML-like syntax from JavaScript functions.', 'Use fragments (<></>) to avoid unnecessary wrapper divs.', 'Every list item needs a unique key prop.', 'Expressions in JSX use curly braces {}.'] },
    { title: 'Props & State', content: `Props (properties) are read-only data passed from parent to child components. They flow one way — downward. A parent decides what data a child receives, and the child cannot modify its own props.\n\nState is mutable data owned by the component itself. When state changes, the component re-renders with the new data. useState is the primary hook for managing state in functional components.\n\nThe key rule: "Lift state up." When two sibling components need to share data, move the state to their common parent and pass it down as props. The parent becomes the "single source of truth."\n\nState updates are batched and asynchronous. React groups multiple setState calls and re-renders once for performance. When the new state depends on the previous state, use the functional updater: setCount(prev => prev + 1).`, code: `import { useState } from 'react';\n\nfunction Counter() {\n  const [count, setCount] = useState(0);\n\n  return (\n    <div>\n      <p>Count: {count}</p>\n      <button onClick={() => setCount(prev => prev + 1)}>+1</button>\n      <button onClick={() => setCount(0)}>Reset</button>\n    </div>\n  );\n}\n\n// Lifting state up\nfunction App() {\n  const [selectedId, setSelectedId] = useState(null);\n\n  return (\n    <div>\n      <Sidebar\n        selectedId={selectedId}\n        onSelect={(id) => setSelectedId(id)}  // Callback prop\n      />\n      <MainContent itemId={selectedId} />       \n    </div>\n  );\n}`, codeLabel: 'Props & State Management', keyPoints: ['Props flow down (parent → child), read-only.', 'State is owned by the component, triggers re-renders.', 'Use functional updater when state depends on previous value.', '"Lift state up" to share data between siblings.'] },
    { title: 'Hooks (useState, useEffect, useContext)', content: `Hooks are functions that let you "hook into" React features from functional components. They were introduced in React 16.8 and eliminated the need for class components.\n\nuseState manages component state. useEffect runs side effects (data fetching, subscriptions, timers) after render. The dependency array controls when it re-runs: [] runs once on mount, [value] runs when value changes, no array runs every render. Return a cleanup function for subscriptions and timers.\n\nuseContext accesses shared data (theme, auth, language) without passing props through every level ("prop drilling"). Create context with createContext(), provide values with <Provider>, and consume with useContext().\n\nOther important hooks: useRef (persist values across renders without re-rendering, access DOM elements), useMemo (cache expensive calculations), useCallback (cache functions to prevent unnecessary child re-renders).`, code: `import { useState, useEffect, useContext, createContext } from 'react';\n\n// useEffect for data fetching\nfunction UserProfile({ userId }) {\n  const [user, setUser] = useState(null);\n  const [loading, setLoading] = useState(true);\n\n  useEffect(() => {\n    let cancelled = false; // Cleanup flag\n\n    async function fetchUser() {\n      setLoading(true);\n      const res = await fetch(\`/api/users/\${userId}\`);\n      const data = await res.json();\n      if (!cancelled) {\n        setUser(data);\n        setLoading(false);\n      }\n    }\n    fetchUser();\n\n    return () => { cancelled = true; }; // Cleanup\n  }, [userId]); // Re-run when userId changes\n\n  if (loading) return <p>Loading...</p>;\n  return <h1>{user.name}</h1>;\n}\n\n// useContext for theme\nconst ThemeContext = createContext('light');\n\nfunction App() {\n  return (\n    <ThemeContext.Provider value="dark">\n      <Toolbar />\n    </ThemeContext.Provider>\n  );\n}\n\nfunction Toolbar() {\n  const theme = useContext(ThemeContext); // "dark"\n  return <div className={theme}>...</div>;\n}`, codeLabel: 'React Hooks', keyPoints: ['useEffect dependency array controls when effects run.', 'Always return cleanup functions from useEffect.', 'useContext eliminates "prop drilling" for global data.', 'useRef persists values without causing re-renders.'] },
    { title: 'React Router & Navigation', content: `React Router (react-router-dom) is the standard library for client-side routing in React SPAs. It maps URL paths to components, enabling navigation without full page reloads.\n\nBrowserRouter wraps the app and enables HTML5 history-based routing. Routes defines the route configuration — each Route maps a path to a component. Nested routes create layouts with shared UI (header/footer) and outlet areas for child content.\n\nNavLink and Link create navigation links. NavLink automatically applies an "active" class when the current URL matches, making it ideal for navigation menus. useParams() extracts URL parameters, and useNavigate() enables programmatic navigation.`, code: `import { BrowserRouter, Routes, Route, NavLink, useParams, useNavigate } from 'react-router-dom';\n\nfunction App() {\n  return (\n    <BrowserRouter>\n      <nav>\n        <NavLink to="/" className={({isActive}) =>\n          isActive ? 'active' : ''\n        }>Home</NavLink>\n        <NavLink to="/courses">Courses</NavLink>\n      </nav>\n\n      <Routes>\n        <Route path="/" element={<Home />} />\n        <Route path="/courses" element={<Courses />} />\n        <Route path="/courses/:id" element={<CourseDetail />} />\n        <Route path="*" element={<NotFound />} />\n      </Routes>\n    </BrowserRouter>\n  );\n}\n\n// Dynamic route parameter\nfunction CourseDetail() {\n  const { id } = useParams();\n  const navigate = useNavigate();\n\n  return (\n    <div>\n      <h1>Course: {id}</h1>\n      <button onClick={() => navigate('/')}>Go Home</button>\n    </div>\n  );\n}`, codeLabel: 'React Router Setup', keyPoints: ['BrowserRouter wraps the entire app for routing.', 'NavLink adds active class for current route styling.', 'useParams() extracts dynamic URL segments.', 'useNavigate() for programmatic navigation.'] },
    { title: 'Build & Deploy', content: `npm run build compiles your React app into optimized static files (HTML, CSS, JS) in the dist/ or build/ folder. These files can be served by any static file server.\n\nBuild optimization: React automatically splits code into chunks, minifies JavaScript, compresses CSS, and applies tree-shaking to remove unused code.\n\nDeployment options: Vercel (zero-config, great for Next.js), Netlify (drag-and-drop deployment), GitHub Pages (free for static sites), AWS S3 + CloudFront (scalable CDN), and Docker/Nginx (self-hosted). For SPAs with client-side routing, configure the server to redirect all requests to index.html.`, code: `# Build for production\nnpm run build\n\n# Preview the build locally\nnpm run preview\n\n# Deploy to Vercel\nnpx vercel --prod\n\n# Deploy to Netlify\nnpx netlify-cli deploy --prod --dir=dist\n\n# Nginx config for SPA routing\nserver {\n  listen 80;\n  root /usr/share/nginx/html;\n  index index.html;\n\n  location / {\n    try_files $uri $uri/ /index.html;\n  }\n}\n\n# Docker deployment\nFROM node:20-alpine AS build\nWORKDIR /app\nCOPY package*.json .\nRUN npm ci\nCOPY . .\nRUN npm run build\n\nFROM nginx:alpine\nCOPY --from=build /app/dist /usr/share/nginx/html`, codeLabel: 'Build & Deploy', keyPoints: ['npm run build creates optimized static files.', 'Vercel and Netlify offer zero-config deployment.', 'Configure server to redirect all routes to index.html.', 'Docker + Nginx for self-hosted production deployment.'] }
  ]
};
